import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";

const root = process.cwd();
const sidebarPath = join(root, "web/src/components/dashboard/sidebar.tsx");
const layoutPath = join(root, "web/src/app/layout.tsx");
const logoPath = join(root, "web/src/assets/lopest-logo.png");
const faviconPath = join(root, "web/src/app/favicon.ico");
const applePath = join(root, "web/src/app/apple-icon.png");

for (const path of [sidebarPath, layoutPath]) {
  if (!existsSync(path)) throw new Error(`Falta archivo requerido: ${path}`);
}

function writeBase64(path, value) {
  mkdirSync(dirname(path), { recursive: true });
  writeFileSync(path, Buffer.from(value, "base64"));
}

writeBase64(logoPath, "");
writeBase64(faviconPath, "");
writeBase64(applePath, "");

let sidebar = readFileSync(sidebarPath, "utf8");

const staticLogoImport = 'import lopestLogo from "@/assets/lopest-logo.png";';
const navigationImport = 'import { dashboardNavigation } from "@/config/navigation";';

if (!sidebar.includes('import Image from "next/image";')) {
  sidebar = sidebar.replace(
    'import Link from "next/link";',
    'import Image from "next/image";\nimport Link from "next/link";',
  );
}

if (!sidebar.includes(staticLogoImport)) {
  if (!sidebar.includes(navigationImport)) {
    throw new Error("No se encontro el import de dashboardNavigation en sidebar.tsx.");
  }
  sidebar = sidebar.replace(
    navigationImport,
    `${navigationImport}\n${staticLogoImport}`,
  );
}

sidebar = sidebar.replace('src="/brand/lopest-logo.png"', 'src={lopestLogo}');

if (!sidebar.includes('src={lopestLogo}')) {
  throw new Error(
    "No se encontro el logo anterior /brand/lopest-logo.png en sidebar.tsx. " +
    "Comparte el bloque actual de marca antes de aplicar otro parche.",
  );
}

writeFileSync(sidebarPath, sidebar, "utf8");

let layout = readFileSync(layoutPath, "utf8");
layout = layout.replace('title: "Create Next App"', 'title: "Créditos Lopest"');
layout = layout.replace(
  'description: "Generated by create next app"',
  'description: "Gestión de clientes, créditos, cuotas y cartera de Créditos Lopest."',
);
layout = layout.replace('lang="en"', 'lang="es"');
writeFileSync(layoutPath, layout, "utf8");

console.log("[OK] Logo instalado como import estatico en web/src/assets.");
console.log("[OK] Favicon simplificado instalado para legibilidad a 16/32 px.");
console.log("[OK] Apple icon y metadata conservados/actualizados.");
